#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5+5;
int n,dep[maxn],rt1,rt2;
vector<int> g[maxn];
void dfs(int u,int fa){
	if(dep[u]>dep[rt1]){
		rt1=u;
	}
	for(auto v:g[u]){
		if(v==fa){
			continue;
		}
		dep[v]=dep[u]+1;
		dfs(v,u);
	}
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<n;i++){
		int a,b;
		cin>>a>>b;
		g[a].emplace_back(b);
		g[b].emplace_back(a);
	}
	dfs(1,0);
	rt2=rt1;
	dep[rt1]=0;
	dfs(rt1,0);
	cout<<dep[rt1];
	return 0;
}
